@Injectable()
export class ParseObjectIdPipe implements PipeTransform {
  transform(value: string): Types.ObjectId {
    const isValidObjectId = Types.ObjectId.isValid(value);

    if (!isValidObjectId) {
      throw new BadRequestException(
        `Invalid ObjectId: '${value}' is not a valid MongoDB ObjectId`,
      );
    }

    return new Types.ObjectId(value);
  }
}

const createPassportContext =
  (request: any, response: any) =>
  (type: string | string[], options: any, callback: Function) =>
    new Promise<void>((resolve, reject) =>
      passport.authenticate(type, options, (err, user, info, status) => {
        try {
          request.authInfo = info;
          return resolve(callback(err, user, info, status));
        } catch (err) {
          reject(err);
        }
      })(request, response, (err: any) => (err ? reject(err) : resolve()))
    );

async onApplicationShutdown(): Promise<void> {
  const dataSource = this.moduleRef.get<DataSource>(
    getDataSourceToken(this.options as DataSourceOptions) as Type<DataSource>,
  );
  try {
    if (dataSource && dataSource.isInitialized) {
      await dataSource.destroy();
    }
  } catch (e: any) {
    this.logger.error(e?.message);
  } finally {
    DataSourceNameRegistry.unregister(
      getDataSourceName(this.options as DataSourceOptions),
    );
  }
}

import { DEFAULT_DATA_SOURCE_NAME } from '../typeorm.constants';

export class DuplicateDataSourceException extends Error {
  constructor(dataSourceName: string) {
    const isDefault = dataSourceName === DEFAULT_DATA_SOURCE_NAME;
    const descriptor = isDefault ? 'default (unnamed)' : `"${dataSourceName}"`;
    super(
      `A data source with the ${descriptor} name is already registered. ` +
        `Multiple data sources must be registered with unique names; otherwise, ` +
        `they will override each other. Please assign a unique "name" property ` +
        `to each TypeOrmModule.forRoot()/forRootAsync() registration.`,
    );
  }
}

@Injectable({ scope: Scope.REQUEST })
export class Guard implements CanActivate {
  static COUNTER = 0;
  static REQUEST_SCOPED_DATA = [] as number[];

  constructor(@Inject('REQUEST_ID') private readonly requestId: number) {
    Guard.COUNTER++;
  }

  canActivate(
    context: ExecutionContext,
  ): boolean | Promise<boolean> | Observable<boolean> {
    Guard.REQUEST_SCOPED_DATA.push(this.requestId);
    return true;
  }
}

@Injectable({ scope: Scope.REQUEST })
export class Interceptor implements NestInterceptor {
  static COUNTER = 0;
  static REQUEST_SCOPED_DATA = [] as number[];

  constructor(@Inject('REQUEST_ID') private readonly requestId: number) {
    Interceptor.COUNTER++;
  }

  intercept(context: ExecutionContext, call: CallHandler): Observable<any> {
    Interceptor.REQUEST_SCOPED_DATA.push(this.requestId);
    return call.handle();
  }
}

